import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
import json
import os

def main(myblob: func.InputStream):

    credential = DefaultAzureCredential()

    # Access Blob Storage
    blob_service_client = BlobServiceClient(account_url=f"https://{os.getenv('BLOB_STORAGE_ACCOUNT')}.blob.core.windows.net", credential=credential)
    blob_content = myblob.read().decode('utf-8')

    # Process data (example code, you may modify as per your processing needs)
    processed_data = {"content": blob_content, "metadata": "processed"}

    # Access Cosmos DB
    cosmos_client = CosmosClient(os.getenv('COSMOS_ENDPOINT'), credential=credential)
    database_name = os.getenv('COSMOS_DATABASE_NAME')
    container_name = os.getenv('COSMOS_CONTAINER_NAME')
    
    database = cosmos_client.get_database_client(database_name)
    container = database.get_container_client(container_name)

    # Write to Cosmos DB
    container.upsert_item(processed_data)

    # Send Notification via Event Grid
    event_grid_endpoint = os.getenv('EVENT_GRID_TOPIC_ENDPOINT')
    event_grid_client = EventGridPublisherClient(event_grid_endpoint, credential=credential)

    event = EventGridEvent(
        subject="New Blob Processed",
        event_type="BlobProcessed",
        data=processed_data,
        data_version="1.0"
    )

    event_grid_client.send([event]) 

# Ensure environment variables are set for BLOB_STORAGE_ACCOUNT, COSMOS_ENDPOINT, COSMOS_DATABASE_NAME, COSMOS_CONTAINER_NAME, EVENT_GRID_TOPIC_ENDPOINT